<?php session_start(); require_once "db.php"; require_once "helpers.php"; require_login(); $uid=current_user_id();
if($_SERVER["REQUEST_METHOD"]==="POST"){ $first=clean_text($_POST["first_name"]??"",80); $last=clean_text($_POST["last_name"]??"",80); $bio=clean_text($_POST["bio"]??"",1000); $stmt=$conn->prepare("UPDATE users SET first_name=?,last_name=?,bio=? WHERE id=?"); $stmt->bind_param("sssi",$first,$last,$bio,$uid); $stmt->execute(); $_SESSION["user_name"]=$first; log_activity($conn,$uid,"update_settings","user",$uid,"Profile updated."); header("Location: settings.php?saved=1"); exit; }
$stmt=$conn->prepare("SELECT first_name,last_name,email,bio FROM users WHERE id=?"); $stmt->bind_param("i",$uid); $stmt->execute(); $user=$stmt->get_result()->fetch_assoc(); ?>
<!doctype html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Settings | SirChef</title><link rel="stylesheet" href="../styles/main.css"><link rel="stylesheet" href="../styles/settings.css"><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css" rel="stylesheet"></head><body><?php include "header.php"; ?><main class="settings-page"><form class="settings-card" method="post"><h1>Account Settings</h1><?php if(isset($_GET["saved"])): ?><div class="alert alert-success">Settings saved.</div><?php endif; ?><label>First name</label><input class="form-control mb-3" name="first_name" value="<?= e($user["first_name"]) ?>" required><label>Last name</label><input class="form-control mb-3" name="last_name" value="<?= e($user["last_name"]) ?>" required><label>Email</label><input class="form-control mb-3" value="<?= e($user["email"]) ?>" disabled><label>Bio</label><textarea class="form-control mb-3" name="bio" rows="4"><?= e($user["bio"]) ?></textarea><button class="btn btn-bohemian">Save Changes</button></form></main><script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js"></script></body></html>
